INSERT INTO tools (slug, name, tagline, description, logo_url, website_url, affiliate_url, tags, pricing_type, pricing_free_tier, pricing_starting_price, rating, review_count, featured, trending, editor_pick, pros, cons, use_cases)
VALUES

-- 1. Harvey AI
('harvey-ai', 'Harvey', 'AI platform for law firms and legal teams with deep legal domain expertise',
'Harvey is an enterprise AI platform built specifically for legal professionals at law firms and corporate legal departments. Unlike general-purpose AI assistants, Harvey is trained on legal data and understands contract language, case law, and regulatory frameworks at a level that general models often miss. Law firms use Harvey for contract review and due diligence, legal research and case preparation, document drafting, and regulatory compliance analysis. The platform processes large document sets, extracts key clauses, and surfaces relevant precedents at a speed that would take associates hours to match manually. Enterprise security standards are central to the platform design, with data isolation and audit logging built in for regulated environments. Harvey is enterprise-only with custom pricing based on firm size and usage volume. For large law firms and corporate legal departments handling significant document volumes, Harvey delivers measurable time savings on routine legal work and frees senior attorneys for higher-value strategic analysis that requires human judgment.',
'https://www.google.com/s2/favicons?domain=harvey.ai&sz=64',
'https://harvey.ai', 'https://harvey.ai',
ARRAY['legal-ai', 'writing-ai'], 'paid', false, 99.00, 4.5, 650, false, true, false,
ARRAY['Built specifically for legal workflows and trained on legal data', 'Processes large document sets for due diligence and contract review', 'Enterprise-grade security with data isolation and audit logging', 'Understands legal terminology better than general-purpose AI tools'],
ARRAY['Enterprise-only - not accessible for solo attorneys or small firms', 'Requires sales engagement and onboarding - no self-serve access', 'Higher cost than general-purpose AI alternatives'],
ARRAY['Contract review and due diligence for law firms', 'Legal research and case preparation at scale', 'Document drafting and regulatory compliance analysis']),

-- 2. Clio
('clio', 'Clio', 'Cloud-based legal practice management platform for law firms of all sizes',
'Clio is the leading cloud-based legal practice management platform, used by over 150,000 legal professionals across 90 countries to run their firms. The platform covers the operational side of legal practice: client intake, matter management, time tracking, billing, document storage, and client communications. Clio Duo, the AI layer, helps attorneys draft client communications, summarise case notes, pull relevant matter details during calls, and automate routine documentation tasks. Unlike specialised legal AI tools focused purely on contract review or legal research, Clio is the operational hub that integrates with court filing systems, payment processors, and calendar tools. The platform is particularly well-suited to solo practitioners and small to mid-size law firms who need one system to manage both the legal and administrative sides of their practice. Plans start at $49 per user per month. The AI features are included in higher-tier plans and continue to expand with each product update, making Clio an evolving AI platform rather than a static tool.',
'https://www.google.com/s2/favicons?domain=clio.com&sz=64',
'https://clio.com', 'https://clio.com',
